import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CompetitorPrice {
  competitor: string;
  price: number;
}

interface ProductData {
  product: {
    name: string;
    currentPrice: number;
    competitorPrices: CompetitorPrice[];
  };
  priceTrend: number[];
}

export default function Widget() {
  const productData = response.data as ProductData;
  const { product, priceTrend } = productData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FAF3E0' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              {product.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#795548' }}>
              ${product.currentPrice.toFixed(2)}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {product.competitorPrices.slice(0, 3).map((competitorPrice) => (
              <Chip
                key={competitorPrice.competitor}
                label={`${competitorPrice.competitor}: $${competitorPrice.price.toFixed(2)}`}
                sx={{ fontSize: '11px', bgcolor: '#FFC107', color: '#5D4037' }}
              />
            ))}
          </Stack>

          <Box>
            <LineChart
              height={120}
              series={[
                {
                  data: priceTrend,
                  color: '#FF5722',
                  curve: 'linear',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: [0, 1, 2, 3, 4, 5, 6], hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
